from flask import Flask, request, jsonify, abort
from flask_login import current_user, login_required
from your_database_module import get_post_by_id, delete_post, is_admin

app = Flask(__name__)

@app.route('/posts/<int:post_id>', methods=['DELETE'])
@login_required
def delete_post_endpoint(post_id):
    post = get_post_by_id(post_id)

    if post is None:
        abort(404, description="Post not found")

    if post.user_id != current_user.id:
        abort(403, description="You do not have permission to delete this post")

    if is_admin(current_user):
        # Optional: Admins can delete any post
        delete_post(post_id)
        return jsonify({"message": "Post deleted successfully"}), 200

    delete_post(post_id)
    return jsonify({"message": "Post deleted successfully"}), 200

